/**
 * @name 蜀安首页方案A V3 单页导出
 * @mode axure
 */
import React, { useEffect, useMemo } from 'react';
import { AnnotationViewer } from '@axhub/annotation';
import type { AnnotationSourceDocument, AnnotationViewerOptions } from '@axhub/annotation';
import '../system-replica-base/style.css';
import { defineHashPageRoute, useHashPage } from '../../common/useHashPage';
import { ShuanHomeCommandV3Page } from '../system-replica-base/pages/ShuanHomeCommandV3';
import { shuanDrilldownRoutePages } from '../system-replica-base/pages/shuan-drilldowns';
import type { ShuanHomeVariant } from '../system-replica-base/pages/ShuanHomeConcepts';
import annotationSourceDocument from './annotation-source.json';

const route = defineHashPageRoute([
  { id: 'shuan-home-command-v3', title: '蜀安首页方案A V3' },
  ...shuanDrilldownRoutePages.filter((page) => page.id !== 'shuan-home-command-v3-wireframes'),
], { defaultPageId: 'shuan-home-command-v3' });

function Component() {
  const { page, setPage } = useHashPage(route);

  useEffect(() => {
    document.body.dataset.shuanV3ExportVisual = 'true';
    const style = document.createElement('style');
    style.id = 'shuan-v3-export-annotation-hide';
    style.textContent = '#__axhub_annotation_host__{display:none!important;}';
    document.head.appendChild(style);
    return () => {
      delete document.body.dataset.shuanV3ExportVisual;
      style.remove();
    };
  }, []);

  const annotationOptions = useMemo<AnnotationViewerOptions>(() => ({
    showToolbar: false,
    showThemeToggle: false,
    showColorFilter: false,
    emptyWhenNoData: false,
    toolbarEdge: 'right',
    currentPageId: page,
    zIndex: 1500,
  }), [page]);

  const handleVariantChange = (_variant: ShuanHomeVariant) => {
    setPage('shuan-home-command-v3');
  };

  return (
    <>
      <ShuanHomeCommandV3Page
        variant="command"
        onVariantChange={handleVariantChange}
        onOpenPage={setPage}
        activeOverlayPage={page === 'shuan-home-command-v3' ? null : page}
      />
      <AnnotationViewer
        source={annotationSourceDocument as unknown as AnnotationSourceDocument}
        options={annotationOptions}
      />
    </>
  );
}

export default Component;

  if (activeOverlayPage.includes('illegal-campaign')) return '首页';
  if (activeOverlayPage.includes('illegal') || activeOverlayPage.includes('algorithm')) return '首页';
  if (activeOverlayPage.includes('daily-regulation')) return '首页';
  if (activeOverlayPage.includes('personnel')) return '从业人员管理';
  if (activeOverlayPage.includes('production')) return '生产管理';
  if (activeOverlayPage === 'system-config') return '系统设置';
  return '首页';
}

function TopHeader({ onOpenPage, activeOverlayPage }: { onOpenPage?: (pageId: string) => void; activeOverlayPage?: string | null }) {
  const activeNavLabel = getActiveTopNavLabel(activeOverlayPage);
  return (
    <header className="shuan-header" data-annotation-id="shuan-v3-header">
      <div className="shuan-brand"><span className="shuan-emblem"><img src={shuanLogoUrl} alt="" /></span><div className="shuan-title">“蜀安”煤矿多源异构监测系统</div></div>
      <nav className="command-nav" aria-label="系统顶部导航">{navItems.map(([label, icon]) => <button key={label} type="button" className={label === activeNavLabel ? 'active' : ''} onClick={() => onOpenPage?.(navPageMap[label] || 'shuan-home-command-v3')}><CockpitIcon name={icon} /><span>{label}</span></button>)}</nav>
      <div className="shuan-top-tools"><button type="button" className="shuan-tool-round shuan-video-entry" aria-label="视频入口" onClick={() => onOpenPage?.('shuan-home-command-v3-video-dispatch')}><Video /></button><button type="button" className="shuan-tool-badge" aria-label="报警消息"><CockpitIcon name="bell" /><b>18</b></button><button type="button" className="shuan-tool-round" aria-label="用户"><UserRound /></button><span className="shuan-user">李明远 <ChevronDown /></span><button type="button" className="shuan-icon-tool" aria-label="设置"><Settings /></button></div>
    </header>
  );
}

function RegulatedMinePanel({ onOpenPage }: { onOpenPage?: (pageId: string) => void }) {
  return (
    <Panel
      title="煤矿生产状态统计"
      className="regulated-mine-panel regulated-mine-panel-v3"
      titleAction={<MoreButton pageId="shuan-home-command-v3-production-status" onOpenPage={onOpenPage} />}
      action={<div className="mine-status-topline"><span>煤矿总数</span><strong>{SICHUAN_TOTAL_MINES}</strong><em>处</em></div>}
    >
      <div className="mine-status-card-grid">
        {mineStatusRows.map(({ label, value, tone }) => (
          <article key={label} className={`mine-status-card tone-${tone}`}>
            <div className="mine-status-card-copy">
              <b>{label}</b>
              <strong>{value}</strong>
              <em>处</em>
            </div>
          </article>
        ))}
      </div>
    </Panel>
  );
}

function GasHazardPanel() {
  return (
    <Panel title="矿井瓦斯等级" className="hazard-panel gas-hazard-panel">
      <div className="hazard-panel-body">
        <div className="gas-hazard-legend">
          {gasHazardRows.map((item) => (
            <div key={item.label} className="gas-hazard-legend-row">
              <span>{item.label}</span>
              <strong>{item.value}</strong>
              <em>{item.percent}</em>
            </div>
          ))}
        </div>
        <div className="gas-hazard-ring-wrap">
          <div className="gas-hazard-ring" aria-label="煤矿瓦斯灾害分布环图">
            <div className="gas-hazard-ring-core">
              <CockpitIcon name="gas-flame" />
            </div>
          </div>
        </div>
      </div>
    </Panel>
  );
}

function HydroHazardPanel() {
  return (
    <Panel title="矿井水文地质类型" className="hazard-panel hydro-hazard-panel">
      <div className="hydro-hazard-list">
        {hydroHazardRows.map((item) => (
          <div key={item.label} className={`hydro-hazard-row tone-${item.tone}`}>
            <span className="hydro-hazard-label">{item.label}</span>
            <div className="hydro-hazard-bar"><i /></div>
            <strong>{item.value}</strong>
            <em>{item.percent}</em>
          </div>
        ))}

